var raw=$input.first().json;
function pj(x){if(typeof x!=='string')return x;try{return JSON.parse(x)}catch(e){return null}}
function isO(v){return v!==null&&typeof v==='object'&&!Array.isArray(v)}
function g(o,k1,k2){if(!isO(o))return null;var v=o[k1];if(v!=null&&v!=='')return v;if(k2){v=o[k2];if(v!=null&&v!=='')return v}return null}
var payload=isO(raw)?raw:{};
if(isO(raw)&&raw.body!==undefined)payload=typeof raw.body==='string'?pj(raw.body):raw.body;
if(!isO(payload))payload={};
var data=isO(payload.data)?payload.data:payload;
if(!isO(data))data=payload;
var tenantId=g(data,'tenantId','tenant_id')||g(payload,'tenantId','tenant_id')||g(raw,'tenantId');
var transferId=g(data,'transferId','transfer_id')||g(payload,'transferId','transfer_id');
if(!tenantId||!transferId)return [{json:{_error:true,message:'tenantId et transferId requis'}}];
return [{json:{tenantId,transferId}}];

var p = $('02. Parser').first().json;
var query = `BEGIN TRANSACTION;
UPDATE stock_transfers SET statut = 'confirmee', updated_at = NOW() WHERE id = '${p.transferId}' AND tenant_id = '${p.tenantId}';
UPDATE stock_levels sl SET quantity = quantity - stl.quantity, updated_at = NOW() FROM stock_transfer_lines stl WHERE stl.transfer_id = '${p.transferId}' AND sl.article_id = stl.article_id AND sl.site_id = (SELECT site_from_id FROM stock_transfers WHERE id = '${p.transferId}') AND sl.tenant_id = '${p.tenantId}';
INSERT INTO stock_movements (id, tenant_id, article_id, site_id, type_mouvement, quantity, date_operation, reference, notes, created_at, updated_at) SELECT gen_random_uuid(), '${p.tenantId}', stl.article_id, st.site_from_id, 'transfert_depart', -stl.quantity, NOW(), st.id, 'Depart de transfert', NOW(), NOW() FROM stock_transfer_lines stl JOIN stock_transfers st ON stl.transfer_id = st.id WHERE st.id = '${p.transferId}';
COMMIT;`;
return [{json:{query}}];
